import{_ as a,o as r,c as t,ah as i}from"./chunks/framework.DsjyFzT5.js";const u=JSON.parse('{"title":"前端常用单位说明","description":"","frontmatter":{"title":"前端常用单位说明","date":"2022-01-01T00:00:00.000Z","category":"FE","tags":["FE"]},"headers":[],"relativePath":"_post/coding-summary/fe/fe-unit.md","filePath":"_post/coding-summary/fe/fe-unit.md"}'),n={name:"_post/coding-summary/fe/fe-unit.md"};function s(l,e,p,o,d,h){return r(),t("div",null,[...e[0]||(e[0]=[i('<h1 id="前端常用单位说明" tabindex="-1">前端常用单位说明 <a class="header-anchor" href="#前端常用单位说明" aria-label="Permalink to &quot;前端常用单位说明&quot;">​</a></h1><h2 id="英寸" tabindex="-1">英寸 <a class="header-anchor" href="#英寸" aria-label="Permalink to &quot;英寸&quot;">​</a></h2><p>1 英寸 = 2.54 厘米</p><div class="language-math vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">math</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1 inch = 2.54cm = 25.4mm</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="屏幕尺寸" tabindex="-1">屏幕尺寸 <a class="header-anchor" href="#屏幕尺寸" aria-label="Permalink to &quot;屏幕尺寸&quot;">​</a></h2><p>如屏幕尺寸 5.2 英寸表示屏幕对角线长度 5.2 英寸</p><h2 id="像素" tabindex="-1">像素 <a class="header-anchor" href="#像素" aria-label="Permalink to &quot;像素&quot;">​</a></h2><p>表示计算机屏幕上能显示的最小单位，像素没有实际物理尺寸的</p><h2 id="物理-分辨率" tabindex="-1">（物理）分辨率 <a class="header-anchor" href="#物理-分辨率" aria-label="Permalink to &quot;（物理）分辨率&quot;">​</a></h2><p>指已知屏幕上的像素块个数</p><p>如：1920*1080：竖向 1920 个像素块，横向 1080 个像素块</p><p>硬件支持</p><h2 id="逻辑分辨率-ios" tabindex="-1">逻辑分辨率(ios) <a class="header-anchor" href="#逻辑分辨率-ios" aria-label="Permalink to &quot;逻辑分辨率(ios)&quot;">​</a></h2><p>和上诉概念相似，软件使用</p><h2 id="屏幕像素密度" tabindex="-1">屏幕像素密度 <a class="header-anchor" href="#屏幕像素密度" aria-label="Permalink to &quot;屏幕像素密度&quot;">​</a></h2><p>1 英寸屏幕对角线上拥有的像素数</p><div class="language-math vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">math</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ppi = √(横向像素²+纵向像素²)/屏幕尺寸</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="长度单位" tabindex="-1">长度单位 <a class="header-anchor" href="#长度单位" aria-label="Permalink to &quot;长度单位&quot;">​</a></h2><ul><li>px：pixel，像素，电子屏幕上组成一幅图画或照片的最基本单元</li></ul><ul><li>ppi: pixel per inch，每英寸像素数，该值越高，则屏幕越细腻</li><li>dpi: dot per inch，每英寸多少点，该值越高，则图片越细腻</li><li>dp(或：dip): dip，Density-independent pixel, 是安卓开发用的长度单位，1dp 表示在屏幕像素点密度为 160ppi 时 1px 长度</li><li>sp: scale-independent pixel，安卓开发用的字体大小单位。 <blockquote><p>sp 和 dp 很类似但唯一的区别是，Android 系统允许用户自定义文字尺寸大小（小、正常、大、超大等等），当文字尺寸是“正常”时 1sp=1dp=0.00625 英寸，而当文字尺寸是“大”或“超大”时，1sp&gt;1dp=0.00625 英寸。类似我们在 windows 里调整字体尺寸以后的效果——窗口大小不变，只有文字大小改变。</p></blockquote></li><li>in:英寸</li><li>mm: 毫米</li></ul><h2 id="参考文章" tabindex="-1">参考文章 <a class="header-anchor" href="#参考文章" aria-label="Permalink to &quot;参考文章&quot;">​</a></h2><p>[1] <a href="http://www.woshipm.com/ucd/198774.html" target="_blank" rel="noreferrer">屏幕尺寸，分辨率，像素，PPI 之间到底什么关系？</a><br> [2] <a href="https://www.jianshu.com/p/41a8ccdf91ed" target="_blank" rel="noreferrer">iPhone 屏幕分辨率和适配规则（基础篇）</a><br> [3] <a href="https://www.zhihu.com/question/40506180" target="_blank" rel="noreferrer">逻辑分辨率和物理分辨率区别</a><br> [4] <a href="https://zhuanlan.zhihu.com/p/26481853" target="_blank" rel="noreferrer">什么是 dp、pt、sp？</a> [5] <a href="https://developer.mozilla.org/zh-CN/docs/Learn/CSS/Building_blocks/Values_and_units" target="_blank" rel="noreferrer">css的值与单位--mdn(推荐)</a><br> [6] <a href="https://developer.android.com/guide/practices/screens_support.html?hl=zh-cn" target="_blank" rel="noreferrer">屏幕兼容性概览</a></p>',22)])])}const m=a(n,[["render",s]]);export{u as __pageData,m as default};
